import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/linux-java-version.Bae4eMgj.js";const a=JSON.parse(`{"title":"在 Linux 上安裝 Java","description":"在 Linux 上安裝 Java 的逐步指南。","frontmatter":{"title":"在 Linux 上安裝 Java","description":"在 Linux 上安裝 Java 的逐步指南。","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"zh_tw/1.21.8/players/installing-java/linux.md","filePath":"versions/1.21.8/translated/zh_tw/players/installing-java/linux.md","lastUpdated":1760721669000}`);var o={name:`zh_tw/1.21.8/players/installing-java/linux.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">在 Linux 上安裝 Java <a class="header-anchor" href="#h1" aria-label="Permalink to “在 Linux 上安裝 Java”">​</a></h1><p>本指南將引導你在 Linux 上安裝 Java 21。</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. 檢查 Java 是否已安裝 <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. 檢查 Java 是否已安裝”">​</a></h2><p>開啟終端機，輸入 <code>java -version</code>，然後按下 <kbd>Enter</kbd> 鍵。</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="終端機中輸入了「java -version」" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>要使用 Minecraft 1.21，你至少需要安裝 Java 21。 如果這個指令顯示任何低於 21 的版本，則需要更新現有的 Java 安裝。 如果這個指令顯示任何低於 21 的版本，則需要更新現有的 Java 安裝。 如果這個指令顯示任何低於 21 的版本，則需要更新現有的 Java 安裝。</p></div><h2 id="2-downloading-and-installing-java" tabindex="-1">2. 下載和安裝 Java 21 <a class="header-anchor" href="#2-downloading-and-installing-java" aria-label="Permalink to “2. 下載和安裝 Java 21”">​</a></h2><p>我們建議使用 OpenJDK 21，它適用於大部分 Linux 發行版。</p><h3 id="arch-linux" tabindex="-1">Arch Linux <a class="header-anchor" href="#arch-linux" aria-label="Permalink to “Arch Linux”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>有關在 Arch Linux 上安裝 Java 的更多資訊，請參閱 <a href="https://wiki.archlinuxcn.org/wiki/Java" target="_blank" rel="noreferrer">Arch Linux Wiki</a>。</p></div><p>你可以從官方儲存庫安裝最新的 JRE：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你在沒有圖形化介面的伺服器上執行，則可以安裝無頭版本：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你打算開發模組，則需要 JDK：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jdk-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="debian-ubuntu" tabindex="-1">Debian／Ubuntu <a class="header-anchor" href="#debian-ubuntu" aria-label="Permalink to “Debian／Ubuntu”">​</a></h3><p>你可以使用 <code>apt</code> 執行以下指令來安裝 Java 21：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openjdk-21-jdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="fedora" tabindex="-1">Fedora <a class="header-anchor" href="#fedora" aria-label="Permalink to “Fedora”">​</a></h3><p>你可以使用 <code>dnf</code> 執行以下指令來安裝 Java 21：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-21-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你不需要圖形化介面，則可以安裝無頭版本：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-21-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你打算開發模組，則需要 JDK：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-21-openjdk-devel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="other-linux-distributions" tabindex="-1">其他 Linux 發行版 <a class="header-anchor" href="#other-linux-distributions" aria-label="Permalink to “其他 Linux 發行版”">​</a></h3><p>如果你的發行版未在上述清單中，你可以從 <a href="https://adoptium.net/temurin/" target="_blank" rel="noreferrer">Eclipse Temurin</a> 下載最新的 JRE。</p><p>如果你打算開發模組，你應參考另一個指南。</p><h2 id="3-verify-that-java-is-installed" tabindex="-1">3. 驗證 Java 21 是否已安裝 <a class="header-anchor" href="#3-verify-that-java-is-installed" aria-label="Permalink to “3. 驗證 Java 21 是否已安裝”">​</a></h2><p>安裝完成後，你可以透過開啟終端機並輸入 <code>java -version</code> 來驗證 Java 21 是否已安裝。</p><p>如果這個命令成功執行，你將看到類似於以前顯示的內容，其中顯示了 Java 版本：</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="終端機中輸入了「java -version」" loading="lazy"></p>`,33)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};